program.command("keygen").description("Generate a new Ed25519 keypair for signing EXIT markers.").addHelpText("after", `
Examples:
  $ exit keygen
    Print a new keypair as JSON (did, publicKey, privateKey)

  $ exit keygen > keypair.json
    Save the keypair to a file

  $ exit keygen | jq -r .privateKey > my.key
    Extract just the private key for use with --key

Security:
  The private key is printed to stdout. Store it securely and never share it.
  Anyone with the private key can sign EXIT markers as your identity.
`).option("--show-keys", "Print private key to stdout (DANGER: do not use in production logs)").action(withErrorHandling((opts) => {
  const kp = generateKeyPair();
  const did = didFromPublicKey(kp.publicKey);
  if (opts.showKeys) {
    console.log(
      JSON.stringify(
        {
          did,
          publicKey: toHex3(kp.publicKey),
          privateKey: toHex3(kp.privateKey)
        },
        null,
        2
      )
    );
  } else {
    const keyFileName = `${did.replace(/[^a-zA-Z0-9]/g, "_")}.key`;
    (0, import_node_fs3.writeFileSync)(keyFileName, toHex3(kp.privateKey), { mode: 384 });
    console.log(
      JSON.stringify(
        {
          did,
          publicKey: toHex3(kp.publicKey),
          privateKeyFile: keyFileName,
          privateKey: "[REDACTED \u2014 saved to file. Use --show-keys to print to stdout instead]"
        },
        null,
        2
      )
    );
    process.stderr.write(`\u26A0 Private key written to ${keyFileName} (mode 0600)
`);
  }
}));
